mapper.select:
SELECT COUNT(1)
FROM jq_sys_user
WHERE username = #{username}
  AND is_deleted = 0

    AND id != #{excludeId}

SELECT DISTINCT u.id FROM jq_sys_user u INNER JOIN jq_sys_user_role ur ON ur.user_id = u.id WHERE u.is_deleted = 0 AND u.status = 1 AND ur.role_id IN
#{roleId}
ORDER BY u.id ASC

SELECT id FROM jq_sys_user WHERE is_deleted = 0 AND status = 1 AND dept_id IN
#{deptId}
ORDER BY id ASC

SELECT id FROM jq_sys_user WHERE is_deleted = 0 AND status = 1 AND id IN
#{userId}
ORDER BY id ASC
